
.chat-screen {
  position: relative;
  height: 100%;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.status-card {
  margin: 10px 13px 6px;
  padding: 10px 12px;
  border-radius: 18px;
  background: linear-gradient(135deg, rgba(49, 199, 176, 0.18), rgba(255, 255, 255, 0.72));
  border: 1px solid rgba(49, 199, 176, 0.18);
  box-shadow: 0 12px 24px rgba(15, 23, 42, 0.08);

  .label {
    color: var(--phone-accent-deep);
    font-size: 10px;
    font-weight: 800;
    letter-spacing: 0.08em;
  }

  strong {
    display: block;
    margin-top: 2px;
    font-size: 15px;
    color: var(--phone-text);
  }

  p {
    margin: 3px 0 0;
    color: var(--phone-muted);
    font-size: 11px;
    overflow-wrap: anywhere;
  }
}

.message-list {
  min-height: 0;
  flex: 1;
  padding: 7px 12px 12px;
  display: flex;
  flex-direction: column;
  gap: 10px;
  overflow-y: auto;
  scrollbar-width: thin;
  scrollbar-color: rgba(107, 122, 144, 0.35) transparent;

  &::-webkit-scrollbar {
    width: 4px;
  }

  &::-webkit-scrollbar-thumb {
    border-radius: 999px;
    background: rgba(107, 122, 144, 0.32);
  }
}
